INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '在局域网中仅某台主机上无法访问域名为 www. coc. com 的网站 (其他主机访问正常)，在该主机上 HUT ping 命令时有显示信息如下: C:>ping www. ccc. com Pinging www. ccc. com [202. 117. 112.36] with 32 bytes of data: Reply from 202. 117. 112. 36:Destination net unreachable. Reply from 202. 117. 112. 36:Destination net unreachable. Reply from 202. 117. 112. 36:Destination net unreachable. Reply from 202. 117.112. 36:Destination net unreachable. Ping statistics for 202.117. 112. 36: Packets: Sent =4, Received =4, Lost=0(0% loss), Approximate round trip times in milli-seconds: Minimum = Oms, Maximum = Oms, Average= Oms', '["A. FEL TCP/IP 协议配置错误", "B. 该主机设置的DNS 服务器工作不正常", "C. 该主机遭受 ARP 攻击导致网关地址错误", "D. 该主机所在网络或网站所在网络中配置了 ACL 拦截规则"]', '', '', 2, '2015年综合知识', '2015,综合知识', 2015);
