INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '网络开发过程包括需求分析、通信规范分析、逻辑网络设计、物理网络设计、安装和维护等五个 阶段。以下关于网络开发过程的叙述中，正确的是(35) 。', '["A. 需求分析阶段应尽量明确定义用户需求，输出需求规范、通信规范", "B. 逻辑网络设计阶段设计人员一般更加关注于网络层的连接图", "C. 物理网络设计阶段要输出网络物理结构图、布线方案、IP 地址方案等", "D. 安装和维护阶段要确定设备和部件清单、安装测斌计划，进行安装调试"]', '', '', 2, '2015年综合知识', '2015,综合知识', 2015);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '0 等多种资源的实时监控，将外部 IP 地址映射为多个内部 IP 地址; 〈2) 数据库服务器采用高可用 性集群系统，使用 Oracle 数据库，采用双活工作模式。对比方案一和方案二中的服务器负载均衡策 略，下列描述中错误的是(36) 。 两个方案都采用了高可用性集群系统，对比单活和双活两种工作模式，下列描述中错误的是(37) 。', '["A. 方案一中对外公开的 IP 地址是负载均衡设备的 IP 地址", "B. 方案二中对每次 TCP 连接请求动态使用一个内部 IP 地址进行响应", "C. 方案一可以保证各个内部服务器间的 CPU. 10 的负载均衡", "D. 方案二的负载均衡策略使得服务器的资源分配更加合理"]', '', '', 2, '2015年综合知识', '2015,综合知识', 2015);